const raw = $input.first().json;
const input = raw.body || raw;
let channel = 'unknown';
let userId = 'default';
let message = '';
let messageId = null;

// WhatsApp Meta Cloud API
if (input.entry && input.entry[0]?.changes?.[0]?.value?.messages?.[0]) {
  const waMsg = input.entry[0].changes[0].value.messages[0];
  channel = 'whatsapp';
  userId = waMsg.from;
  message = waMsg.text?.body || waMsg.type || '';
  messageId = waMsg.id;
}
// Telegram
else if (input.message?.chat?.id) {
  channel = 'telegram';
  userId = String(input.message.chat.id);
  message = input.message.text || '';
  messageId = String(input.message.message_id);
}
// Gmail
else if (input.from || input.snippet) {
  channel = 'gmail';
  userId = input.from || 'email_user';
  message = input.snippet || input.subject || '';
  messageId = input.id;
}
// Fallback / test
else {
  channel = input.channel || 'test';
  userId = String(input.userId || input.from || 'test_user');
  message = input.message || input.text || input.body || 'test message';
}

// Hard guard — never proceed with empty message
if (!message || message.trim() === '') {
  return [{ json: { skip: true, reason: 'empty message', channel, userId } }];
}

return [{ json: { channel, userId, message: message.trim(), timestamp: new Date().toISOString(), messageId, raw } }];

const data = $input.first().json;
if (data.skip) {
  return [];
}
return [{ json: data }];

const normalizedData = $('OpenCode Normalizer').first().json;
const historyRows = $input.all().map(i => i.json).filter(r => r.message && r.role);
// Oldest first for correct conversation order
const history = [...historyRows].reverse();

const messages = [
  {
    role: 'system',
    content: `You are LOISEKK, a fast and intelligent personal assistant. Rules:
- Answer directly and concisely
- For web searches, output exactly: TOOL:web_search:<your search query>
- Never explain that you are going to search — just output the TOOL line
- For everything else, respond naturally in plain text
- Current time: ${new Date().toISOString()}`
  },
  ...history.map(row => ({ role: row.role, content: row.message })),
  { role: 'user', content: normalizedData.message }
];

return [{
  json: {
    messages,
    userId: normalizedData.userId,
    channel: normalizedData.channel,
    userMessage: normalizedData.message,
    timestamp: normalizedData.timestamp
  }
}];

const response = $input.first().json;
const buildPromptData = $('Build Prompt').first().json;

const assistantMessage = response.message?.content || response.response || 'I could not process that request. Please try again.';

// Structured tool call detection
const toolMatch = assistantMessage.match(/TOOL:(\w+):(.+)/);
let toolCall = null;
if (toolMatch) {
  toolCall = { tool: toolMatch[1].trim(), args: toolMatch[2].trim() };
}

// Clean tool prefix from display response
const cleanResponse = toolCall
  ? assistantMessage.replace(/TOOL:\w+:[^\n]+/, '').trim() || 'Searching...'
  : assistantMessage.trim();

return [{
  json: {
    response: cleanResponse,
    toolCall,
    userId: buildPromptData.userId,
    channel: buildPromptData.channel,
    userMessage: buildPromptData.userMessage,
    timestamp: buildPromptData.timestamp
  }
}];

const query = $('Response Parser').first().json.toolCall.args;
const url = 'https://html.duckduckgo.com/html/';
const body = 'q=' + encodeURIComponent(query) + '&t=h_&ia=web';

try {
  const resp = await fetch(url, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
      'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36'
    },
    body
  });
  const html = await resp.text();
  const results = [];
  const resultRegex = /<a rel="nofollow" class="result__a" href="([^"]+)"[^>]*>([^<]+)<\/a>[\s\S]*?class="result__snippet"[^>]*>([^<]+)</gi;
  let match;
  while ((match = resultRegex.exec(html)) !== null && results.length < 5) {
    let href = match[1];
    try { href = new URL(href).searchParams.get('uddg') || href; } catch(e) {}
    results.push({ title: match[2].trim(), url: href, description: match[3].trim() });
  }
  return [{ json: { web: { results }, query } }];
} catch(e) {
  return [{ json: { web: { results: [] }, query, error: e.message } }];
}

// Merge search summary into final response shape
const searchResult = $input.first().json;
const parserData = $('Response Parser').first().json;
const summary = searchResult.message?.content || searchResult.response || 'Could not retrieve search results.';

return [{
  json: {
    response: summary.trim(),
    userId: parserData.userId,
    channel: parserData.channel,
    userMessage: parserData.userMessage,
    timestamp: parserData.timestamp
  }
}];

// Daily scheduled task — always returns at least one item so n8n doesn't error
const now = new Date();
return [{
  json: {
    task: 'daily_heartbeat',
    status: 'completed',
    timestamp: now.toISOString(),
    message: 'Scheduled check ran at ' + now.toLocaleTimeString()
  }
}];
